import{_ as e,o,c as a,Q as r}from"./chunks/framework.1b6086f5.js";const m=JSON.parse('{"title":"docker volume","description":"","frontmatter":{},"headers":[],"relativePath":"doc/DevOps/Docker/基础/volume.md","filePath":"packages/doc/src/DevOps/Docker/基础/volume.md","lastUpdated":1703174217000}'),t={name:"doc/DevOps/Docker/基础/volume.md"},c=r('<h1 id="docker-volume" tabindex="-1">docker volume <a class="header-anchor" href="#docker-volume" aria-label="Permalink to &quot;docker volume&quot;">​</a></h1><h3 id="cached-delegated-consistent" tabindex="-1">:cached,:delegated,:consistent <a class="header-anchor" href="#cached-delegated-consistent" aria-label="Permalink to &quot;:cached,:delegated,:consistent&quot;">​</a></h3><p>通过在 docker run -v， --volume 的 option 中指定 cached 或 delegated，可以显着提高 Docker Desktop for Mac 上已装载卷访问的性能。您可以根据情况调整所需的一致性级别：</p><p>consistent：默认值，完美的一致性，即主机和容器实时一致。 cached：主机具有权威性。容器执行的写操作对主机是立即可见的，但是在主机上执行的写操作可能不会立即反应在容器内。 delegated：容器的内容具有权威性。提供最弱保证，由容器执行的写操作可能不会立即反映在主机文件系统上，提供的性能要比其他配置好得多。</p><h3 id="rw-ro" tabindex="-1">rw,ro <a class="header-anchor" href="#rw-ro" aria-label="Permalink to &quot;rw,ro&quot;">​</a></h3><p>而其中的rw、ro和不指定模式，是比较重要的一个环节，关系到宿主机与容器的文件、文件夹变化关系，下面来一一详解</p><p>一、不指定</p><p>（1）文件：宿主机修改该文件后容器里面看不到变化；容器里面修改该文件，宿主机也看不到变化</p><p>（2）文件夹：不管是宿主机还是容器内修改、新增、删除文件，都会相互同步</p><p>二、ro</p><p>（1）文件：容器内不能修改，会提示read-only</p><p>（2）文件夹：容器内不能修改、新增、删除文件夹中的文件，会提示read-only</p><p>三、rw</p><p>（1）文件：不管是宿主机还是容器内修改，都会相互同步，但容器内不允许删除，会提示Device or resource busy；宿主机删除文件，容器内的不会被同步</p><p>（2）文件夹：不管是宿主机还是容器内修改、新增、删除文件，都会相互同步</p>',15),d=[c];function s(p,n,l,i,h,_){return o(),a("div",null,d)}const k=e(t,[["render",s]]);export{m as __pageData,k as default};
